const KEY = [2, 1, 1, 1, 4, 1, 4, 1, 1, 1, 2, 1, 2, 3, 3, 1, 3, 1, 1, 1, 1, 1, 4, 1, 4, 3, 2, 2, 2, 3, 2, 3, 1, 1, 3, 1, 2, 3, 3, 2, 2, 3, 2, 3, 3, 1, 2, 3, 3, 2, 1, 2, 2, 2, 1, 3, 3, 3, 2, 3, 1, 1, 2, 1, 1, 1, 3, 3, 2, 3, 2, 1, 2, 2, 3, 1, 1, 1, 1, 1, 1, 2, 3, 2, 1, 2, 1, 2, 3, 1, 3, 2, 3, 2, 1, 3, 1, 1, 3, 1];
if (KEY.length !== 100) { console.error(`KEY length ${KEY.length}`); process.exit(1); }

const RAW = [
  { s: `General Intelligence`, q: `Choose the missing element in the given series: Circle, Square, Triangle, ?`, o: [`Line`, `Rectangle`, `Point`, `Curve`], e: `All the given items are basic geometric shapes. After circle, square, and triangle, the next logical shape in the sequence is rectangle. Thus, correct option is (b).` },
  { s: `General Intelligence`, q: `If in a certain code, PEN is written as QFO, how is BOOK written? SSC 19, 2026, 28, 2026,`, o: [`CPPL`, `DPPM`, `CNOK`, `DQQM`], e: `Paper (Held on 24 Jul Sol: Given: If in a certain code, PEN is written as QFO. 2025 S2) Selection Selection 19, 2026, 28, 2026, Post Post 16:20:21 03:10:57 Logic: Letters are (iHncigrehaesring + 1 place. For, PEN - QFO Secondary) P + 1 = Q, E + 1 =SFim, Nila+r 1 = O Similarly, Paper BOOK - ? (Held on B + 1 = C, O + 1 =2P4, OJul+ 1 = P, K + 1 = L So, BOOK is writte2n02a5s SC2P)PL. Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `Which of the following is different? 64, 81, 100, 121`, o: [`64`, `81`, `100`, `121`], e: `Given: 64, 81, 100, 121 64 = 43 81 = 92 100 = 102 121 = 112 So, 64 is different. Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `In each of the following questions, four words are given. Three are alike in some manner and one is different. Choose the odd one.`, o: [`Velocity`, `Force`, `Energy`, `Length`], e: `Force, Energy and Length are scalar quantities. Velocity is a vector quantity (it has both magnitude and direction). So, Velocity is odd one out. Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `In each of the following questions, four words are given. Three are alike in some manner and one is different. Choose the odd one.`, o: [`Communism`, `Capitalism`, `Socialism`, `Geography`], e: `Communism, Capitalism and Socialism are economic/political ideologies. Geography is a subject/discipline, not an ideology. So, Geography is odd one out. Thus, correct option is (d).` },
  { s: `General Intelligence`, q: `Debate is to Knowledge as Training is to ______`, o: [`Skill`, `Fatigue`, `Pressure`, `Discipline`], e: `Given: Debate is to Knowledge as Training is to ______ Debate helps in gaining knowledge. Similarly, Training : ? Training helps in developing a skill. Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `From the word CARELESS, which of the following is NOT a valid English word?`, o: [`CARE`, `LESS`, `SEAL`, `RACELESS`], e: `Given: CARELESS Now, we check each options. Option (a): CARE (Valid word) Letters used: C, A, R, E All these letters are present in CARELESS Option (b): LESS (Valid word) Letters used: L, E, S, S CARELESS contains L, E, and two S's Option (c: SEAL (Valid word) Letters used: S, E, A, L All letters are present in CARELESS Option (d): RACELESS (Not a valid word) Letters used: R, A, C, E, L, E, S, S This word needs two R's, but CARELESS has only one R So, RACELESS word is NOT a valid English word. Thus, correct option is (d).` },
  { s: `General Intelligence`, q: `Find the next number: 1, 4, 9, 16, 25, ?`, o: [`36`, `30`, `49`, `32`], e: `Given: 1, 4, 9, 16, 25, ? Logic: Numbers are increasing perfect square of natural number from 1. 12= 1 22= 4 32= 9 42= 16 52= 25 62= 36 So, the missing term is 36. Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `Choose the correct next step: Plan, Execute, Review, _____`, o: [`Improve`, `Ignore`, `Delay`, `Stop`], e: `Given: Plan, Execute, Review, _____ The sequence represents a standard improvement cycle. Plan decide what to do Execute carry out the plan Review evaluate results After reviewing, the logical next step is to Improve based on feedback and findings. So, the missing term is Improve. Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `If MANGO is coded as 13-1-14-7-15, how is PEACH coded?`, o: [`16-5-1-3-8`, `16-4-1-3-8`, `15-5-1-3-7`, `16-5-2-3-8`], e: `Given: If MANGO is coded as 13-1-14-7-15. Logic: Numbers are coded as place value of letters. For, MANGO = 13-1-14-7-15 M = 13, A = 1, N = 14, G = 7, O = 15 Similarly, PEACH = ? P = 16, E = 5, A = 1, C = 3 , H = 8 So, PEACH is coded as 16-5-1-3-8. Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `If someone disagrees with you during a discussion, what should you do first?`, o: [`Raise your voice`, `Listen to their viewpoint`, `End the discussion`, `Mock their opinion`], e: `Given: If someone disagrees with you during a discussion. Reason: Listening first helps you understand the other person's perspective and leads to a respectful and meaningful discussion. So, Listen to their viewpoint should you do first. Thus, correct option is (b).` },
  { s: `General Intelligence`, q: `What comes next in the series - 12 : 1728 :: 8 : ?`, o: [`512`, `256`, `216`, `729`], e: `Given: 12 : 1728 :: 8 : ? Logic: 1st number3= 2nd number 123= 1728 Similarly, 8:? 83= 512 Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `What comes next in the series - 14 : 196 :: 16 : ?`, o: [`224`, `256`, `272`, `288`], e: `Given: 14 : 196 :: 16 : ? Logic: 1st number2= 2nd number 142= 196 Similarly, 16 : ? 162= 256 Thus, correct option is (b).` },
  { s: `General Intelligence`, q: `If 5 3 = 16 and 7 2 = 18, find 6 4?`, o: [`28`, `24`, `20`, `30`], e: `Given: If 5 3 = 16 and 7 2 = 18 Logic: (1st number + 2nd number) ├Ś 2 = 3rd number For, 5 3 = 16 (5 + 3) ├Ś 2 = 8 ├Ś 2 = 16 For, 7 2 = 18 (7 + 2) ├Ś 2 = 9 ├Ś 2 = 18 Similarly, 6 4? (6 + 4) ├Ś 2 = 10 ├Ś 2 = 20 Thus, correct option is (c).` },
  { s: `General Intelligence`, q: `A teammate looks stressed before a presentation. What is the best response?`, o: [`Tell them to calm down`, `Ignore their feelings`, `Offer support and encouragement`, `Point out their mistakes`], e: `Given: A teammate looks stressed before a presentation. Reason: Offering support helps reduce stress and boosts confidence, leading to better teamwork and performance. So, Offer support and encouragement is the best response. Thus, correct option is (c).` },
  { s: `General Intelligence`, q: `Apply the same letter transformation as in the first pair: BIRD : CJSE :: FISH : ?`, o: [`GJTI`, `FJTH`, `GITH`, `HJTI`], e: `Given: BIRD : CJSE :: FISH : ? Logic: Letters are increasing + 1 place. For, BIRD : CJSE B + 1 = C, I + 1 = J, R + 1 = S, D + 1 = E Similarly, FISH : ? F + 1 = G, I + 1 = J, S + 1 = T, H + 1 = I So, FISH : GJTI Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `A classmate makes a mistake while speaking. How should you react?`, o: [`Laugh at them`, `Correct them loudly`, `Stay silent and attentive`, `Interrupt immediately`], e: `Given: A classmate makes a mistake while speaking. Reason: Being respectful and attentive encourages confidence. Laughing, interrupting, or correcting loudly can embarrass the speaker. So, Stay silent and attentive should you react. Thus, correct option is (c).` },
  { s: `General Intelligence`, q: `Which of the following is an example of cause and effect reasoning?`, o: [`He was late because the bus broke down`, `She enjoys music and art`, `They are friends from school`, `He is tall and strong`], e: `Reason: The sentence clearly shows a cause (the bus broke down) and an effect (he was late). So, He was late because the bus broke down is an example of cause and effect reasoning. Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `If 10 2 = 6 and 14 4 = 9, what is 18 6?`, o: [`12`, `9`, `15`, `6`], e: `Given: If 10 2 = 6 and 14 4 = 9 Logic: (1st number + 2nd number) ├Ě 2 = 3rd number For, 10 2 = 6 (10 + 2) ├Ě 2 = 12 ├Ě 2 = 6 For, 14 4 = 9 (14 + 4) ├Ě 2 = 18 ├Ě 2 = 9 Similarly, 18 6? (18 + 6) ├Ě 2 = 24 ├Ě 2 = 12 Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `Find the next set: AC, EG, IK, MO, ?`, o: [`QS`, `PR`, `QU`, `RS`], e: `Given: AC, EG, IK, MO, ? Logic: Letters are increasing + 4 place. A + 4 = E, E + 4 = I, I + 4 = M, M + 4 = Q C + 4 = G, G + 4 = K, K + 4 = O, O + 4 = S So, the missing term is QS. Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `Statement: "Online classes reduce student engagement." Which option weakens this statement?`, o: [`Studies show engagement was low even before online classes`, `Online classes are flexible`, `Students use digital devices`, `Internet access is common`], e: `Statement: "Online classes reduce student engagement." Explanation: Option A suggests that low engagement existed prior to online classes, which weakens the claim that online classes are the cause of reduced engagement. The other options do not directly challenge the cause┬şeffect relationship in the statement. So, Studies show engagement was low even before online classes weakens of this statement. Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `If 9 # 3 = 6 and 12 # 4 = 8, what is 15 # 5?`, o: [`10`, `12`, `15`, `8`], e: `Given: If 9 # 3 = 6 and 12 # 4 = 8. Logic: 1st number - 2nd number = 3rd number For, 9 # 3 = 6 9-3=6 For, 12 # 4 = 8 12 - 4 = 8 Similarly, 15 # 5? 15 - 5 = 10 Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `In a certain code, GOLD is written as DLOG. How is SILVER written?`, o: [`HRIEVQ`, `EROVIS`, `IROVHS`, `REVLIS`], e: `Given: In a certain code, GOLD is written as DLOG. Logic: Letters are coded as reverse order. For, GOLD - DLOG GOLD DLOG (reverse order) Similarly, SILVER - ? SILVER REVLIS (reverse order) Thus, correct option is (d).` },
  { s: `General Intelligence`, q: `Choose the number that does not belong to the group. 16, 27, 64, 125`, o: [`16`, `27`, `64`, `125`], e: `Given: 16, 27, 64, 125 16 = 42 27 = 33 64 = 43 125 = 53 So, 16 is odd one out. Because 27, 64, 125 are increasing natural number from 3. Thus, correct option is (a).` },
  { s: `General Intelligence`, q: `If 4 3 = 19 and 6 2 = 20, what is 5 4?`, o: [`21`, `24`, `18`, `29`], e: `Given: If 4 3 = 19 and 6 2 = 20 Logic: (1st number ├Ś 2nd number) + (1st number + 2nd number) = 3rd number For, 4 3 = 19 (4 ├Ś 3) + (4 + 3) = 12 + 7 = 19 For, 6 2 = 20 (6 ├Ś 2) + (6 + 2) = 12 + 8 = 20 Similarly, 5 4? (5 ├Ś 4) + (5 + 4) = 20 + 9 = 29 Thus, correct option is (d).` },
  { s: `General Awareness`, q: `How is data for the Global Hunger Index primarily assessed?`, o: [`Through satellite weather data`, `By analysing stock market trends`, `Using indicators like undernourishment and child mortality`, `By measuring internet penetration`], e: `The correct answer is (C) Using indicators like undernourishment and child mortality Explanation: ┬Ě The GHI score is calculated based on four indicators: Undernourishment, Child Stunting, Child Wasting, and Child Mortality. ┬Ě It is published annually by Concern Worldwide and Welthungerhilfe. Information Booster: ┬Ě A high GHI score indicates a higher level of hunger in the country. Additional Knowledge: ┬Ě Stunting refers to low height for age, while Wasting refers to low weight for height.` },
  { s: `General Awareness`, q: `Which sector of the economy is mainly concerned with converting raw materials into finished goods?`, o: [`Primary sector`, `Secondary sector`, `Tertiary sector`, `Quaternary sector`], e: `The correct answer is (B) Secondary sector Explanation: ┬Ě The secondary sector includes industries where finished products are made from natural materials produced in the primary sector. ┬Ě It is also called the industrial or manufacturing sector. Information Booster: ┬Ě Examples include steel factories, car manufacturing, and textile mills. Additional Knowledge: ┬Ě Primary sector (Option A): Direct use of natural resources (Agriculture, Mining). ┬Ě Tertiary sector (Option C): Service sector (Banking, Tourism).` },
  { s: `General Awareness`, q: `What does the Global Innovation Index primarily measure?`, o: [`Military strength of nations`, `Innovation performance of countries`, `Population growth rate`, `Agricultural output levels`], e: `The correct answer is (B) Innovation performance of countries Explanation: ┬Ě The GII ranks world economies according to their innovation capabilities. ┬Ě It is published by the World Intellectual Property Organization (WIPO). Information Booster: ┬Ě India has seen a significant jump in GII rankings over the last few years, reflecting a growing startup ecosystem. Additional Knowledge: ┬Ě It takes into account parameters like human capital, research, infrastructure, and market sophistication.` },
  { s: `General Awareness`, q: `Who is eligible to benefit under the Pradhan Mantri Jan Dhan Yojana (PMJDY)?`, o: [`Only government employees`, `Any Indian citizen without a bank account`, `Only senior citizens`, `Only rural farmers`], e: `The correct answer is (B) Any Indian citizen without a bank account Explanation: ┬Ě PMJDY is a National Mission for Financial Inclusion to ensure access to financial services, namely, basic savings & deposit accounts, remittance, credit, insurance, and pension in an affordable manner. ┬Ě It allows individuals to open 'Zero Balance' accounts. Information Booster: ┬Ě Benefits include a RuPay Debit Card, an inbuilt accident insurance cover of 2 lakh, and an overdraft facility of up to 10,000. Additional Knowledge: ┬Ě The scheme was launched on August 28, 2014.` },
  { s: `General Awareness`, q: `Which Schedule of the Constitution contains the list of official languages?`, o: [`Fifth Schedule`, `Sixth Schedule`, `Eighth Schedule`, `Ninth Schedule`], e: `The correct answer is (C) Eighth Schedule Explanation: ┬Ě The Eighth Schedule of the Indian Constitution lists 22 oCffoicpiaylrilganhgt u┬ęag2e0s2.6 Adda247 ┬Ě Originally, there were 14 languages; others were added by various amendments. Information Booster: ┬Ě Sindhi, Konkani, Manipuri, Nepali, Bodo, Dogri, Maithili, and Santhali were added later. Additional Knowledge: ┬Ě Ninth Schedule (Option D): Contains acts and regulations that are protected from judicial review (with some exceptions).` },
  { s: `General Awareness`, q: `Which of the following statements correctly describes how multicellular organisms digest their food?`, o: [`They digest food only outside the body.`, `They digest food in specialised digestive organs.`, `They absorb food directly through the cell membrane.`, `They use pseudopodia to engulf food particles.`], e: `The correct answer is (B) They digest food in specialised digestive organs. Explanation: ┬Ě In multicellular organisms like humans, the digestive system consists of a group of organs (stomach, intestines, etc.) that work together to break down complex food into simpler forms. ┬Ě This is an example of extra-cellular digestion occurring within a specialized tube. Information Booster: ┬Ě Enzymes play a crucial role in the chemical breakdown of food. Additional Knowledge: ┬Ě Pseudopodia (Option D): Used by unicellular organisms like Amoeba to capture food.` },
  { s: `General Awareness`, q: `What is the primary objective of the International Solar Alliance (ISA)?`, o: [`Promote fossil fuel trade`, `Increase coal production`, `Strengthen global solar energy cooperation`, `Reduce agricultural exports`], e: `The correct answer is (C) Strengthen global solar energy cooperation Explanation: ┬Ě The ISA is an alliance of more than 120 countries, initiated by India and France. ┬Ě Its goal is to reduce reliance on fossil fuels and promote efficient consumption of solar energy to reduce the carbon footprint. Information Booster: ┬Ě The ISA is headquartered in Gurugram, India. Additional Knowledge: ┬Ě It was launched at the COP21 Climate Conference in Paris in 2015.` },
  { s: `General Awareness`, q: `Which Indian author wrote the novel The God of Small Things?`, o: [`Arundhati Roy`, `Jhumpa Lahiri`, `Anita Desai`, `Vikram Seth`], e: `The correct answer is (A) Arundhati Roy Explanation: ┬Ě Arundhati Roy's debut novel 'The God of Small Things' wCoonptyhriegBhot o┬ęke2r0P2r6izAedidna1294977. ┬Ě The book explores how small, seemingly insignificant things shape people's lives and destinies, set in the state of Kerala. Information Booster: ┬Ě She is also a well-known political activist and author of several non-fiction works. Additional Knowledge: ┬Ě Vikram Seth (Option D): Famous for 'A Suitable Boy'.` },
  { s: `General Awareness`, q: `How does the World Health Organization (WHO) support global health equity?`, o: [`By promoting universal health coverage and affordable healthcare access`, `By restricting medical research to developed nations`, `By limiting vaccine production`, `By focusing only on private healthcare systems`], e: `The correct answer is (A) By promoting universal health coverage and affordable healthcare access Explanation: ┬Ě WHO works globally to promote health, keep the world safe, and serve the vulnerable. ┬Ě Its primary goal is to ensure that a billion more people have universal health coverage. Information Booster: ┬Ě WHO was established on April 7, 1948, which is celebrated as World Health Day. Additional Knowledge: ┬Ě Its headquarters are in Geneva, Switzerland.` },
  { s: `General Awareness`, q: `How many players are there in a standard football (soccer) team on the field?`, o: [`9`, `10`, `11`, `12`], e: `The correct answer is (C) 11 Explanation: ┬Ě A standard football match is played by two teams, each with a maximum of 11 players on the field at one time. ┬Ě One of these players must be a goalkeeper. Information Booster: ┬Ě Football is governed globally by FIFA (Federation Internationale de Football Association). Additional Knowledge: ┬Ě A match consists of two halves of 45 minutes each.` },
  { s: `General Awareness`, q: `The Dronacharya Award is given for excellence in which field?`, o: [`Sports Coaching`, `Literature`, `Science`, `Music`], e: `The correct answer is (A) Sports Coaching Explanation: ┬Ě The Dronacharya Award is the highest sports coaching honor in India. ┬Ě It is named after Dronacharya, the legendary guru of theCPoapnydraigvhats ┬ęan2d0K2a6uAradvdaas2i4n7the Mahabharata. Information Booster: ┬Ě It was instituted in 1985. Additional Knowledge: ┬Ě Major Dhyan Chand Khel Ratna Award: India's highest sporting honor for athletes.` },
  { s: `General Awareness`, q: `What is the primary objective of the G20 Leaders' Summit?`, o: [`To establish a global military alliance`, `To promote international economic cooperation and financial stability`, `To regulate cultural exchanges among nations`, `To control global migration policies`], e: `The correct answer is (B) To promote international economic cooperation and financial stability Explanation: ┬Ě The G20 is the premier forum for international economic cooperation. ┬Ě It plays a critical role in shaping and strengthening global architecture and governance on all major international economic issues. Information Booster: ┬Ě India held the G20 Presidency from December 2022 to November 2023 under the theme 'Vasudhaiva Kutumbakam'. Additional Knowledge: ┬Ě The G20 consists of 19 countries, the European Union, and the African Union (added in 2023).` },
  { s: `General Awareness`, q: `Which planet is known as the "Red Planet"?`, o: [`Venus`, `Jupiter`, `Mars`, `Saturn`], e: `The correct answer is (C) Mars Explanation: ┬Ě Mars is called the 'Red Planet' because of the prevalence of iron oxide (rust) on its surface, which gives it a reddish appearance. ┬Ě It is the fourth planet from the Sun. Information Booster: ┬Ě Mars has the largest volcano in the solar system, Olympus Mons. Additional Knowledge: ┬Ě Venus (Option A): Known as the Morning/Evening star and the hottest planet. ┬Ě Jupiter (Option B): The largest planet in our solar system.` },
  { s: `General Awareness`, q: `Onam is primarily celebrated in which Indian state?`, o: [`Tamil Nadu`, `Karnataka`, `Kerala`, `Andhra Pradesh`], e: `The correct answer is (C) Kerala Explanation: ┬Ě Onam is the biggest harvest festival of Kerala. ┬Ě It commemorates the home-coming of the mythical KingCoMpayhriagbhatli┬ę. 2026 Adda247 Information Booster: ┬Ě Key attractions of Onam include the Pookalam (flower carpet), Vallam Kali (boat race), and the Onam Sadya (grand feast). Additional Knowledge: ┬Ě Tamil Nadu (Option A): Primarily celebrates Pongal as its harvest festival.` },
  { s: `General Awareness`, q: `Which of the following statements correctly describes how green plants prepare their food?`, o: [`They absorb ready-made food from the soil.`, `They prepare food using sunlight, carbon dioxide, and water.`, `They depend entirely on animals for nutrition.`, `They digest food outside their body before absorption.`], e: `The correct answer is (B) They prepare food using sunlight, carbon dioxide, and water. Explanation: ┬Ě This process is called Photosynthesis. ┬Ě Plants use chlorophyll (a green pigment) to capture solar energy and convert inorganic substances into glucose (organic food). Information Booster: ┬Ě Oxygen is released as a byproduct of photosynthesis. Additional Knowledge: ┬Ě Plants are known as 'Autotrophs' because they can make their own food.` },
  { s: `General Awareness`, q: `Who was appointed as the Governor of the Reserve Bank of India on 11 December 2024?`, o: [`Shaktikanta Das`, `Sanjay Malhotra`, `Urjit Patel`, `Raghuram Rajan`], e: `The correct answer is (B) Sanjay Malhotra Explanation: ┬Ě Sanjay Malhotra, an IAS officer of the 1990 batch, was appointed as the 26th Governor of the RBI following the completion of Shaktikanta Das's tenure. ┬Ě Before this, he served as the Revenue Secretary. Information Booster: ┬Ě The RBI Governor is appointed by the Appointments Committee of the Cabinet (ACC). Additional Knowledge: ┬Ě Shaktikanta Das (Option A): Served as the 25th Governor and was the first to receive a second extension in several decades.` },
  { s: `General Awareness`, q: `What was the main objective behind the introduction of the Insolvency and Bankruptcy Code (IBC), 2016?`, o: [`To increase direct taxes`, `To simplify company registration`, `To resolve insolvency in a time-bound manner`, `To promote exports`], e: `The correct answer is (C) To resolve insolvency in a time-bound manner Explanation: ┬Ě IBC was introduced to consolidate and amend laws relating to reorganization and insolvency resolution of corporate persons, partnership firms, and individuals. ┬Ě The goal is to maximize the value of assets and promote entrepreneurship. Information Booster: ┬Ě The National Company Law Tribunal (NCLT) is the adjudicating authority for corporate insolvency. Additional Knowledge: ┬Ě Before IBC, India had multiple laws like SARFAESI and SICA, which led to long delays in resolving bad loans.` },
  { s: `General Awareness`, q: `Which statement best explains the Law of Conservation of Energy?`, o: [`Force equals mass multiplied by acceleration`, `Energy can neither be created nor destroyed`, `Every action has an equal and opposite reaction`, `Pressure is force per unit area`], e: `The correct answer is (B) Energy can neither be created nor destroyed Explanation: ┬Ě The Law of Conservation of Energy states that the total energy of an isolated system remains constant. ┬Ě Energy can only be transformed from one form to another (e.g., potential to kinetic energy). Information Booster: ┬Ě This is also the First Law of Thermodynamics. Additional Knowledge: ┬Ě Option A: Newton's Second Law of Motion. ┬Ě Option C: Newton's Third Law of Motion.` },
  { s: `General Awareness`, q: `The Nyaya school of philosophy is primarily concerned with which aspect?`, o: [`Rituals and sacrifices`, `Devotional practices`, `Logic and reasoning`, `Meditation and renunciation`], e: `The correct answer is (C) Logic and reasoning Explanation: ┬Ě Founded by Sage Gautama, the Nyaya school believes in obtaining valid knowledge through four sources: Perception, Inference, Comparison, and Testimony. ┬Ě It uses a systematic logical framework to reach conclusions. Information Booster: ┬Ě It is one of the six orthodox (Astika) schools of Indian philosophy. Additional Knowledge: ┬Ě Mimamsa (Option A): Concerned with rituals and interpretation of Vedas. ┬Ě Yoga (Option D): Concerned with meditation and physical discipline.` },
  { s: `General Awareness`, q: `Which region in India is known for black soil suitable for cotton cultivation?`, o: [`Indo-Gangetic Plain`, `Thar Desert`, `Deccan Plateau`, `Himalayan Region`], e: `The correct answer is (C) Deccan Plateau Explanation: ┬Ě Black soil (also known as Regur soil) is formed by the weathering of lava rocks. ┬Ě It is highly moisture-retentive and rich in iron and lime, making it ideal for cotton, earning it the name 'Black Cotton Soil'. Information Booster: ┬Ě Major areas include Maharashtra, Gujarat, and parts of Madhya Pradesh (Deccan Trap region). Additional Knowledge: ┬Ě Alluvial soil (found in Indo-Gangetic Plain) is the most widespread soil in India.` },
  { s: `General Awareness`, q: `Which monument is an example of Indo-Islamic architecture?`, o: [`Qutub Minar`, `Konark Sun Temple`, `Brihadeeswara Temple`, `Meenakshi Temple`], e: `The correct answer is (A) Qutub Minar Explanation: ┬Ě Qutub Minar was built starting in 1192 by Qutb-ud-din Aibak, the founder of the Delhi Sultanate. ┬Ě It is a classic example of early Indo-Islamic style, featuring calligraphy and geometric patterns. Information Booster: ┬Ě It is a UNESCO World Heritage site and is the tallest brick minaret in the world. Additional Knowledge: ┬Ě Options B, C, and D are examples of indigenous Hindu temple architecture (Nagara and Dravida styles).` },
  { s: `General Awareness`, q: `The Mathura art style is primarily associated with which religion?`, o: [`Jainism`, `Buddhism`, `Zoroastrianism`, `Christianity`], e: `The correct answer is (B) Buddhism Explanation: ┬Ě The Mathura school of art flourished during the Kushana period. ┬Ě While it produced images for Brahmanism and Jainism too, it is most famous for the early indigenous human representations of the Buddha. Information Booster: ┬Ě Unlike the Gandhara school (which used grey schist), the Mathura school used spotted red sandstone. Additional Knowledge: ┬Ě The Buddha in Mathura art is often shown with a smiling face and a muscular body.` },
  { s: `General Awareness`, q: `Which government launched the Pradhan Mantri Ujjwala Yojana?`, o: [`Government of Maharashtra`, `Government of Gujarat`, `Government of India`, `Government of Rajasthan`], e: `The correct answer is (C) Government of India Explanation: ┬Ě PMUY was launched by the Ministry of Petroleum and Natural Gas, Government of India. ┬Ě It aims to safeguard the health of women and children by providing them with a clean cooking fuel ┬ş LPG. Information Booster: ┬Ě The scheme was launched in May 2016 from Ballia, Uttar Pradesh. Additional Knowledge: ┬Ě Ujjwala 2.0 was later launched to cover migrant families who might not have address proofs.` },
  { s: `General Awareness`, q: `Which Article of the Constitution deals with the protection of life and personal liberty?`, o: [`Article 14`, `Article 19`, `Article 21`, `Article 32`], e: `The correct answer is (C) Article 21 Explanation: ┬Ě Article 21 states that 'No person shall be deprived of his life or personal liberty except according to procedure established by law'. ┬Ě It is available to both citizens and non-citizens. Information Booster: ┬Ě The Supreme Court has expanded Article 21 to include the right to privacy, right to clean environment, and right to education. Additional Knowledge: ┬Ě Article 14 (Option A): Right to Equality. ┬Ě Article 32 (Option D): Right to Constitutional Remedies.` },
  { s: `General Awareness`, q: `Which Article of the Indian Constitution guarantees freedom of speech and expression?`, o: [`Article 14`, `Article 19`, `Article 21`, `Article 25`], e: `The correct answer is (B) Article 19 Explanation: ┬Ě Article 19(1)(a) guarantees to all citizens the right to freedom of speech and expression. ┬Ě However, this right is not absolute and is subject to 'reasonable restrictions'. Information Booster: ┬Ě Article 19 also includes the right to assemble peacefully, form associations, and move freely throughout India. Additional Knowledge: ┬Ě Article 25 (Option D): Deals with the freedom of religion.` },
  { s: `Quantitative Aptitude`, q: `The parallel sides of a trapezium differ by 6 cm. Its height is 10 cm and the area is 350 cm2. What are the lengths of the parallel sides?`, o: [`32 cm and 38 cm`, `30 cm and 36 cm`, `35 cm and 41 cm`, `28 cm and 34 cm`], e: `Given: Difference of parallel sides = 6 cm Height = 10 cm Area = 350cm2 Formula Used: Area of trapezium = 1 ├Ś (sum of parallel sides) ├Ś height 2 Solution: Let the parallel sides be a and b where a > b Given, a - b = 6 ...(1) Area = 350 1 (a + b) ├Ś 10 = 350 2 5 (a + b) = 350 a + b = 70 ...(2) Adding (1) and (2): 2a = 76=> a = 38 Substitute a = 38 in (2): 38 + b = 70 => b = 32 The sides are 32 cm and 38 cm. Final Answer So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `A right prism has a trapezium-shaped base with parallel sides 8 cm and 12 cm, the distance between them is 6 cm, and the prism height is 20 cm. Find the volume.`, o: [`1000cm3`, `1200cm3`, `1400cm3`, `900cm3`], e: `Given: Parallel sides = 8 cm and 12 cm Distance between parallel sides (height of base) = 6 cm Height of prism = 20 cm Formula Used: Volume of prism = Area of Base ├Ś Height 1 Area of trapezium = ├Ś (sum of parallel sides) ├Ś height 2 Solution: Area of base (Trapezium) = 1 (8 + 12) ├Ś 6 2 cm2 = 1 ├Ś 20 ├Ś 6 = 60 2 Volume = 60 ├Ś 20 = 1200 cm3 Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `If the lateral surface area of a right circular cylinder is 880cm2and the height is 10 cm, find the radius.`, o: [`12 cm`, `14 cm`, `7 cm`, `21 cm`], e: `Given: Lateral Surface Area (LSA) = 880 cm2 Height (h) = 10 cm Formula Used: LSA of cylinder = 2 \\pi r h Solution: 2 ├Ś 22 ├Ś r ├Ś 10 = 880 7 440 r = 880 7 880 ├Ś 7 r= 440 r = 2 ├Ś 7 = 14 cm Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `A solid metal cylinder with radius 12 cm and height 5 cm is melted and recast into 9 smaller cylinders of the same height. What is the radius of each small cylinder?`, o: [`3 cm`, `4 cm`, `2 cm`, `6 cm`], e: `Given: Radius of large cylinder (R) = 12 cm Height of large cylinder (H) = 5 cm Number of small cylinders (n) = 9 Height of small cylinder (h) = 5 cm Formula Used: Volume of cylinder = r2h Volume of large cylinder = n ├ŚVolume of small cylinder Solution: Let the radius of the small cylinder be r (12)2 ├Ś 5 = 9 ├Ś r2 ├Ś 5 144 = 9r2 r2 = 144 = 16 9 r = 16 = 4 cm Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `In a circle, chords AB and CD intersect externally at point P. If APC = 40and arc AC subtends 100at the center, what is the angle subtended by arc BD at the center?`, o: [`20`, `40`, `60`, `80`], e: `Given: APC = 40 Angle subtended by arc AC at center = 100 Formula Used: For chords intersecting externally at P: 1 P = Angle(Major Arc) - Angle(Minor Arc) 2 Solution: Let the angle subtended by arc BD be x 40 = 1 (100 - x) 2 80 = 100 - x x = 100 - 80 = 20 Final Answer So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `Assertion (A): Two circles touching each other externally have exactly three common tangents. Reason (R): One direct common tangent and two transverse common tangents can be drawn.`, o: [`Both A and R are true, and R is the correct explanation of A`, `Both A and R are true, but R is not the correct explanation of A`, `A is true, but R is false`, `A is false, but R is true`], e: `Given: Assertion (A): Two circles touching externally have 3 common tangents. Reason (R): One direct and two transverse tangents. Solution: When two circles touch each other externally: 1. They have two direct common tangents. 2. They have one transverse common tangent passing through the point of contact. Total common tangents = 3. So, Assertion (A) is True. Reason (R) states "One direct and two transverse", which is incorrect. It should be "Two direct and one transverse". So, Reason (R) is False. Final Answer So the correct answer is (c)` },
  { s: `Quantitative Aptitude`, q: `If x = 13, what is the value of x + x?`, o: [`156`, `169`, `182`, `195`], e: `Given: x = 13 Solution: Squaring both sides: x = 132 = 169 We need to find x + x: x + x = 169 + 13 = 182 Final Answer So the correct answer is (c)` },
  { s: `Quantitative Aptitude`, q: `Which of the following numbers is a perfect square of an even number?`, o: [`169`, `225`, `256`, `289`], e: `Solution: We check each option: A) 169 = 132(Odd number squared) B) 225 = 152(Odd number squared) C) 256 = 162(Even number squared) D) 289 = 172(Odd number squared) The question asks for a perfect square of an even number. 16 is an even number and its square is 256. Final Answer So the correct answer is (c)` },
  { s: `Quantitative Aptitude`, q: `Two numbers 4562 and 4634 are divided by a greatest two-digit number and leave the same remainder. What is the sum of the digits of the divisor?`, o: [`7`, `9`, `8`, `6`], e: `Given: Numbers: 4562 and 4634 They leave the same remainder when divided by a 2-digit number. Formula Used: If two numbers leave the same remainder when divided by n, then n must be a factor of their difference. Solution: Difference = 4634 - 4562 = 72 Factors of 72: 1, 2, 3, 4, 6, 8, 9, 12, 18, 24, 36, 72. Two-digit factors are: 12, 18, 24, 36, 72. We need to find the sum of digits of the divisor. Possible sums: 12: 1+2=3 18: 1+8=9 24: 2+4=6 36: 3+6=9 72: 7+2=9 From the options, 9 is the correct match (Option B). Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `Which of the following sets is NOT a subset of Integers?`, o: [`Natural numbers`, `Whole numbers`, `Rational numbers`, `Negative numbers`], e: `Solution: Natural numbers {N} are {1, 2, 3, ..}, which are integers. Whole numbers {W} are {0, 1, 2, ...}, which are integers. Negative numbers (e.g., -1, -5) are integers. 1 Rational numbers {Q} include fractions like 2 , which are NOT integers. Therefore, the set of Rational numbers is not a subset of Integers. Final Answer So the correct answer is (c)` },
  { s: `Quantitative Aptitude`, q: `Match the sets in Column I with Column II: Column I Column II`, o: [`A-2, B-1`, `A-1, B-2`, `A-2, B-2`, `A-1, B-1`], e: `Solution: Column I: A. Natural Numbers: These start from 1. Set: {1, 2, 3, ...}. Matches with 2. B. Integers: These include negative numbers, zero, and positive numbers. Set: {...-2, -1, 0, 1, 2...}. Matches with 1. Result: A-2, B-1. Final Answer So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `A fund of 2400 is to be distributed between X and Y in the ratio 3:2. Before distribution, 400 is deducted for fees, and the remaining amount is increased by 10% as a bonus. How much does X receive?`, o: [`1320`, `1400`, `1250`, `1100`], e: `Given: Total Fund = 2400 Fee deducted = 400 Bonus = 10% Ratio X:Y = 3:2 Solution: Amount after fee deduction = 2400 - 400 = 2000 Amount after 10% bonus increase = 2000 + 10% of 2000 = 2000 + 200 = 2200 This amount is distributed in 3:2. Total parts = 3 + 2 = 5 3 X's share = ├Ś 2200 5 = 3├Ś 440 = 1320 Final Answer So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `The average score of a player in 12 innings is 35. How many runs must he score in the 13th inning to raise his average to 37?`, o: [`59`, `61`, `63`, `55`], e: `Given: Average of 12 innings = 35 New Average after 13 innings = 37 Formula Used: S um = Average ├Ś Number of items Solution: Total runs in 12 innings = 12 ├Ś 35 = 420 Total runs required for 13 innings = 13 ├Ś 37 = 13(40 - 3) = 520 - 39 = 481 Runs in 13th inning = Total13 - Total12 = 481 - 420 = 61 Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `The average of 15 numbers is 50. The average of the first 8 numbers is 48 and the average of the last 8 numbers is 53. Find the 8th number.`, o: [`58`, `45`, `50`, `60`], e: `Given: Average of 15 numbers = 50 Average of first 8 = 48 Average of last 8 = 53 Solution: Sum of 15 numbers = 15 ├Ś 50 = 750 Sum of first 8 numbers = 8 ├Ś 48 = 384 Sum of last 8 numbers = 8 ├Ś53 = 424 The 8th number is included in both the first 8 and the last 8 groups. 8th number = (Sum of first 8 + Sum of last 8) - Total Sum = (384 + 424) - 750 = 808 - 750 = 58 Final Answer So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `A number is increased by 50% and then decreased by 40%. What is the net percentage change?`, o: [`10% decrease`, `10% increase`, `20% decrease`, `No change`], e: `Given: Increase = +50% Decrease = -40% Formula Used: xy Net % change = x + y + 100 Solution: Here x = 50 and y = -40 Net change = 50 + (-40) + 50 ├Ś (-40) 2000 100 = 10 - 100 = 10 - 20 = -10% Negative sign indicates a decrease. Final Answer So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `A shopkeeper buys books for 300 each. He marks them at 450. He offers a "Buy 2, Get 1 Free" deal. What is his profit percentage per book sold effectively?`, o: [`0%`, `10%`, `25%`, `50%`], e: `Given: CP per book = 300 MP per book = 450 Offer: Buy 2, Get 1 Free Solution: For a customer buying 2 books, they get 3 books total. Customer pays for 2 books at MP: SP (Total) = 2 ├Ś 450 = 900 Shopkeeper sells 3 books. CP (Total) = 3 ├Ś 300 = 900 Profit = SP - CP = 900 - 900 = 0 Profit % = 0% Final Answer So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `12 men can complete a project in 20 days. How many men are required to complete the same project in 15 days?`, o: [`15 men`, `18 men`, `16 men`, `24 men`], e: `Given: 12 men take 20 days. Find men for 15 days. Formula Used: M D = M D 1 1 2 2 Solution: 12 ├Ś 20 = M2 ├Ś 15 240 = 15M2 M2 = 240 15 M2 = 16 Final Answer So the correct answer is (c)` },
  { s: `Quantitative Aptitude`, q: `A can do a work in 10 days, B in 12 days, and C in 15 days. They start together but C leaves after 2 days. How many more days will A and B take to finish the remaining work?`, o: [`2 days`, `3 days`, `2 days`, `3 days`], e: `Given: Time taken by A = 10 days, B = 12 days, C = 15 days. C leaves after 2 days. Solution: Total Work = LCM(10, 12, 15) = 60 units. Efficiency of A = 60/10 = 6 units/day Efficiency of B = 60/12 = 5 units/day Efficiency of C = 60/15 = 4 units/day Total efficiency (A+B+C) = 6+5+4 = 15 units/day Work done in first 2 days = 15 ├Ś 2 = 30 units. Remaining work = 60 - 30 = 30 units. Now only A and B work. Efficiency of A+B = 6+5 = 11 units/day. Remaining Work 30 Time taken for remaining work = = Efficiency 11 = 2 8 days 11 Final Answer So the correct answer is (c)` },
  { s: `Quantitative Aptitude`, q: `A train 200m long crosses another train 150m long running in the opposite direction in 10 seconds. If the speed of the first train is 70 km/h, find the speed of the second train.`, o: [`50 km/h`, `56 km/h`, `60 km/h`, `45 km/h`], e: `Given: Length of Train 1 (L1) = 200 m Length of Train 2 (L2) = 150 m Time = 10 s Speed of Train 1 (S1) = 70 km/h Formula Used: Relative Speed = L1 + L2 Time For opposite direction, Relative Speed = S1 + S2 Solution: Total Distance = 200 + 150 = 350 m 350 Relative Speed (m/s) = = 35 m/s 10 Convert to km/h: 18 35 ├Ś = 7 ├Ś 18= 126 km/h 5 S1 + S2 = 126 70 + S2 = 126 S2 = 126 - 70 = 56 km/h Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `A person invested 5000 at 4% simple interest and 4000 at 5% simple interest per annum. Find the total interest earned after 2 years.`, o: [`600`, `700`, `800`, `900`], e: `Given: Investment 1: 5000 at 4% Investment 2: 4000 at 5% Time = 2 years Formula Used: P ├ŚR├ŚT SI = 100 Solution: Interest from Inv 1: 5000 ├Ś 4 ├Ś 2 = 50 ├Ś 8 = 400 100 Interest from Inv 2: 4000 ├Ś 5 ├Ś 2 = 40 ├Ś 10 = 400 100 Total Interest = 400 + 400 = 800 Final Answer So the correct answer is (c)` },
  { s: `Quantitative Aptitude`, q: `If cos┬▓╬Ş Ôłĺ sin┬▓╬Ş = 1/2, what is the value of cosÔü┤╬Ş Ôłĺ sinÔü┤╬Ş?`, o: [`1`, `1/2`, `1/4`, `3/4`], e: `Formula: aÔü┤ Ôłĺ bÔü┤ = (a┬▓ Ôłĺ b┬▓)(a┬▓ + b┬▓). cos┬▓╬Ş + sin┬▓╬Ş = 1. cosÔü┤╬Ş Ôłĺ sinÔü┤╬Ş = (cos┬▓╬Ş Ôłĺ sin┬▓╬Ş)(cos┬▓╬Ş + sin┬▓╬Ş) = (1/2)(1) = 1/2. Option B.` },
  { s: `Quantitative Aptitude`, q: `Two observers on the same side of a tower observe its top at angles of elevation 30and 60. If the distance between the observers is 40 meters, find the height of the tower.`, o: [`20 3 m`, `40`, `10 3 m`, `30`], e: `Given: Angles of elevation: 30and60 Distance between observers = 40 m (Same side) Formula Used: d = h(cot 1 - cot 2 )where 1 < 2 Solution: Let height be h 40 = h(cot 30 - cot 60) 40 = h( 3 - 1 ) 3 3-1 40 = h( ) 3 40 = h( 2 ) 3 2h = 40 3 h = 20 3 m Final Answer So the correct answer is (a)` },
  { s: `Quantitative Aptitude`, q: `If x+y = 10 and xy = 20, then the value of x2 + y2is:`, o: [`40`, `60`, `80`, `100`], e: `Given: x + y = 10 xy = 20 Formula Used: ( x + y)2 = x2 + y2 + 2xy Solution: 1 02 = x2 + y2 + 2(20) 100 = x2 + y2 + 40 x2 + y2 = 100 - 40 x2 + y2 = 60 Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `A woman takes a loan of 20,000 at 5% compound interest per annum. Find the total amount she has to pay after 2 years.`, o: [`21,000`, `22,050`, `22,000`, `21,500`], e: `Given: Principal (P) = 20,000 Rate (r) = 5% Time (t) = 2 years Formula Used: Amount (A) = P (1 + r )t 100 Solution: A = 20000(1 + 5 )2 100 A = 20000(1.05)2 A = 20000 ├Ś 1.1025 A = 22050 Final Answer So the correct answer is (b)` },
  { s: `Quantitative Aptitude`, q: `A retailer buys an article for 800. He marks it up by 50%. He then offers a discount of 20% on the marked price. What is his profit percentage?`, o: [`10%`, `15%`, `20%`, `25%`], e: `Given: CP = 800 Markup = 50% Discount = 20% Solution: Marked Price (MP) = 800 + 50% of 800 = 800 + 400 = 1200 Selling Price (SP) = 1200 - 20% of 1200 = 1200 - 240 = 960 Profit = SP - CP = 960 - 800 = 160 160 Profit % = ├Ś 100 800 1 = ├Ś 100= 20% 5 Final Answer So the correct answer is (c)` },
  { s: `English Language`, q: `Change the following from active to passive: They have introduced several measures to improve classroom participation.`, o: [`Several measures have been introduced to improve classroom participation.`, `Several measures were introduced by them to improve classroom participation.`, `Several measures are being introduced by them to improve classroom participation.`, `Several measures are introduced by them for improving classroom participation.`], e: `The correct option is (a). Step-by-step conversion (Active to Passive): Identify the tense: "have introduced" is Present Perfect (Subject + has/have + V3). Identify the object: "several measures" is the object in the active sentence, and it becomes the subject in passive. Passive structure for Present Perfect: Object + has/have been + V3 + (by + subject) + remaining words. Apply the structure: "Several measures have been introduced (by them) to improve classroom participation." The agent "by them" is optional because it is obvious and not essential here. Why other options are incorrect: (b) uses Simple Past "were introduced," which changes the tense and meaning. (c) uses Present Continuous Passive "are being introduced," which is a different tense/aspect. (d) uses Simple Present Passive "a` },
  { s: `English Language`, q: `A sentence is provided in direct speech. From the four given options, choose the one that most accurately conveys the sentence in its corresponding indirect speech. The coach said, "Practice daily to improve."`, o: [`The coach advised practicing daily to improve.`, `The coach said practice daily for improvement.`, `The coach asked me practice everyday.`, `The coach requested to practice daily improve.`], e: `The correct option is (a). Rules for converting Direct to Indirect (Imperative sentences): If the reporting verb is "said" and the reported speech is an order/advice/request, we replace "said" with a suitable verb such as advised/ordered/requested/told depending on meaning. Imperative sentences in indirect speech generally use: advised/told/ordered + object (if needed) + to + base verb. Here, "Practice daily to improve" expresses advice, not a question or narration. Step-by-step transformation: Reporting verb: "The coach said" change to "The coach advised ..." because it is advice. Verb form: "Practice" (base verb) "to practice" or "practicing" (gerund can be used after "advised"). Purpose phrase: "to improve" remains as an infinitive of purpose. Best indirect form: "The coach advised prac` },
  { s: `English Language`, q: `A sentence is provided in indirect speech. From the four given options, choose the one that most accurately conveys the sentence in its corresponding direct speech. She said that she was hungry.`, o: [`She said, "I am hungry."`, `She said, "I was hungry."`, `She said, "I have been hungry."`, `She said, "I will be hungry."`], e: `The correct option is (a). Key rules for converting Indirect to Direct: Pronoun change: Indirect "she" (speaker) becomes direct "I" because the speaker refers to herself in direct speech. Tense restoration: In indirect speech, "was" often appears due to backshifting (especially when the reporting verb is in the past). When converting back to direct speech, we often restore the original present meaning if the statement is a general immediate state. The meaning here indicates a present condition of hunger at the time of speaking, so the natural direct form is: "I am hungry." Step-by-step conversion: "She said that" "She said," "she" "I" "was hungry" "am hungry" (restoring the likely original present statement). Why other options are incorrect: (b) "I was hungry" suggests the hunger was in th` },
  { s: `English Language`, q: `Convert the sentence provided below from its passive voice structure to an active voice structure: The classroom had been cleaned by the students before the teacher arrived.`, o: [`The students had cleaned the classroom before the teacher arrived.`, `The students cleaned the classroom before the teacher arrived.`, `The classroom was cleaned before the teacher arrived.`, `The students have cleaned the classroom before the teacher arrived.`], e: `The correct option is (a). Step-by-step conversion (Passive to Active): Identify tense in passive: "had been cleaned" is Past Perfect Passive. Past Perfect Passive structure: Object + had been + V3 + by + agent. Convert to active (Past Perfect): Agent + had + V3 + object. Agent: "the students" becomes the subject in active. Object: "the classroom" becomes the object in active. Correct active sentence: "The students had cleaned the classroom before the teacher arrived." Why other options are incorrect: (b) is Simple Past ("cleaned"), which changes the sequence of actions implied by Past Perfect. (c) remains in passive voice and does not convert to active. (d) uses Present Perfect ("have cleaned") which is incorrect with the past time reference "before the teacher arrived." So the correct an` },
  { s: `English Language`, q: `Find the word that is spelled correctly and refers to polished manners.`, o: [`Refinement`, `Reffinement`, `Refienment`, `Refinmant`], e: `The correct option is (a). Spelling and meaning: Option (a) "Refinement" is correctly spelt. It refers to improved or polished behaviour, cultured manners, and the process of making something more elegant or pure. (Hindi meaning: / ) Example: Her refinement and polite speech impressed everyone at the formal event. Why the other options are incorrect: (b) Reffinement is incorrect because it wrongly doubles the consonant "f". (c) Refienment is incorrect because the vowel arrangement is wrong; "ei" is not used in the standard spelling. (d) Refinmant is incorrect because "a" is wrongly used in place of "e" in the final syllable "-ment". Meanings of all given options (for comparison): Refinement: Polished manners; improvement in quality ( / ). Reffinement: Not a correct English word ( ). Refien` },
  { s: `English Language`, q: `Change the following from active to passive: We are drafting a comprehensive plan for disaster management.`, o: [`A comprehensive plan for disaster management is being drafted by us.`, `A comprehensive plan for disaster management was drafted by us.`, `A comprehensive plan for disaster management has been drafted by us.`, `A comprehensive plan is drafted by us for disaster management.`], e: `The correct option is (a). Step-by-step conversion (Active to Passive): Identify the tense: "are drafting" is Present Continuous (am/is/are + V-ing). Identify the object: "a comprehensive plan for disaster management" is the object; it becomes the subject in passive. Passive structure for Present Continuous: Object + am/is/are + being + V3 + by + subject. Apply the structure: "A comprehensive plan for disaster management is being drafted by us." Why other options are incorrect: (b) uses Simple Past "was drafted," which changes the tense. (c) uses Present Perfect Passive "has been drafted," which shows completion, not ongoing action. (d) uses Simple Present Passive "is drafted," which suggests habitual action, not an ongoing action. So the correct answer is (a)` },
  { s: `English Language`, q: `Why other options are incorrect: uses Simple Past ÔÇťwas drafted,ÔÇŁ which changes the tense. uses Present Perfect Passive ÔÇťhas been drafted,ÔÇŁ which shows completion, not ongoing action. uses Simple Present Passive ÔÇťis drafted,ÔÇŁ which suggests habitual action, not an ongoing action. So the correct answer is (a)`, o: [`Beneficial`, `Harmful`, `Brief`, `Loud`], e: `The correct option is (b). Meaning of the given word: Pernicious means extremely harmful, damaging, or destructive, especially in a gradual or subtle way. It often indicates a hidden danger that causes serious harm over time. (Hindi meaning: / ) Example (given word): Smoking has pernicious effects on health that may appear slowly but become severe. Meaning of the correct synonym: Harmful means causing injury, damage, or negative effects to a person, thing, or situation. (Hindi meaning: ) Example (correct word): Excessive screen time can be harmful to a child's eyesight. Synonyms (of pernicious): damaging, destructive, detrimental, injurious. Antonyms (of pernicious): beneficial, harmless, helpful, wholesome. Meanings of other given options: (a) Beneficial: producing good results; helpful (` },
  { s: `English Language`, q: `Spot the part of the sentence that contains an error. If there is no error, choose D.`, o: [`She must have reached`, `the station by 6 p.m.`, `because she is looking exhausted last night.`, `No error`], e: `The correct option is (c). Identification of the error: Option (c) contains an error because it mixes a present-time verb form with a past-time marker. Phrase used: "she is looking exhausted last night." "is looking" is Present Continuous (am/is/are + V-ing), which is used for actions happening now or around now. "last night" clearly indicates past time, so the verb should also be in a past form. Corrected form (one appropriate correction): "...because she was looking exhausted last night." (Past Continuous) Or, more natural: "...because she looked exhausted last night." (Simple Past) Grammatical rule used: Time expressions such as "yesterday/last night/last week" require a past tense verb, not a present tense verb. Example (rule usage): She was tired yesterday. / He looked upset last nigh` },
  { s: `English Language`, q: `A sentence is provided in direct speech. From the four given options, choose the one that most accurately conveys the sentence in its corresponding indirect speech. He said, "I will call you in the evening."`, o: [`He said that he will call me in the evening.`, `He said that he would call me in the evening.`, `He said that he will be calling me evening.`, `He said he would calling me in the evening.`], e: `The correct option is (b). Rules for Direct to Indirect (Statement / Future tense): When the reporting verb is in the past ("said"), the tense of the reported clause usually backshifts. Direct: will (future) generally becomes indirect: would (future in the past). Pronoun change: "I" becomes "he" (speaker changes). "you" becomes "me" (listener changes) in the given options. Step-by-step conversion: He said, "I will call you in the evening." Remove quotation marks and use "that": He said that... "I" "he" "will call" "would call" due to backshifting "you" "me" Correct indirect sentence: "He said that he would call me in the evening." Why other options are incorrect: (a) keeps "will," which is generally incorrect with past reporting verb in standard narration rules. (c) is ungrammatical ("me e` },
  { s: `English Language`, q: `A sentence is provided in indirect speech. From the four given options, choose the one that most accurately conveys the sentence in its corresponding direct speech. He asked her whether she had sent the email.`, o: [`He asked, "Have you sent the email?"`, `He said, "Had you send the email?"`, `He asked, "Have I sent the email?"`, `He asked, "Did you sent the email?"`], e: `The correct option is (a). Rules for Indirect to Direct (Yes/No question with whether/if): Indirect "asked whether/if" indicates a Yes/No question in direct speech. We restore the question form with auxiliary verb at the beginning. Pronoun restoration: "she" (listener) becomes "you" in direct speech. Tense restoration: "had sent" (past perfect) is often the backshifted form of "have sent" (present perfect) in direct speech. Step-by-step conversion: He asked her whether she had sent the email. Remove "whether" and use question format: "Have you sent the email?" Keep reporting verb "asked" and add quotation marks. Why other options are incorrect: (b) uses "said" (wrong reporting verb) and incorrect verb form "send" instead of "sent." (c) changes the subject to "I," which is incorrect because` },
  { s: `English Language`, q: `Choose the most suitable option to fill the blank part of the sentence. If the sentence is already correct, select \`No substitution required'. Hardly had the actor entered the hall when the audience called it ___ memorable entry of the night.`, o: [`the more`, `the most`, `most`, `No substitution required`], e: `The correct option is (b). Explanation (Superlative degree and article usage): The phrase "_____ memorable entry of the night" coCmopayreigshtth┬ęe e2n0t2ry6 wAidthdaa2ll4o7ther entries during the night. When something is the highest degree among many, we use the superlative form: most + adjective or adjective + "-est". Superlatives are generally used with the definite article "the": "the most memorable." Correct sentence: "Hardly had the actor entered the hall when the audience called it the most memorable entry of the night." Grammatical rule used: Superlative degree requires "the" before "most/ -est" when referring to a unique highest degree in a group. Example (rule usage): She is the most talented student in the class. Why other options are incorrect: (a) the more is comparative, used ` },
  { s: `English Language`, q: `The hikers rested on the mountain ___.`, o: [`ridge`, `rage`, `rodge`, `rige`], e: `The correct option is (a). Correct word and meaning: Option (a) "ridge" is correctly spelt and fits the context. A ridge is a long narrow raised part of a mountain or hill, often forming a crest or edge. (Hindi meaning: / ) Example: The hikers rested on the ridge and enjoyed the panoramic view of the valley. Why other options are incorrect: (b) rage: means violent anger (); it does not fit the geographical context. (c) rodge: not a standard English word ( / ). (d) rige: incorrect spelling; not acceptable in standard English ( ). Meanings of all options: ridge: mountain edge/crest ( ). rage: intense anger ( ). rodge: not a correct word (). rige: incorrect spelling ( ). So the correct answer is (a)` },
  { s: `English Language`, q: `Arrange the parts to form a correct sentence: P: the spokesperson Q: gave an update R: on the new policy S: to reporters`, o: [`PRSQ`, `PQRS`, `QRPS`, `SPRQ`], e: `The correct option is (b). Correct sentence formation: The correct order is PQRS which gives: "The spokesperson gave an update on the new policy to reporters." Reasoning in steps: P "the spokesperson" is the subject, so it must come first. Q "gave an update" is the verb phrase and must follow the subject. R "on the new policy" explains what the update is about, so it naturally follows "update." S "to reporters" indicates the recipient of the update, typically placed after the object/complement. Why other orders are incorrect: (a) PRSQ places the prepositional phrase "on the new policy" before the verb phrase, breaking normal subject┬şverb order. (c) QRPS begins with a verb phrase without a subject, making it grammatically incorrect. (d) SPRQ begins with a prepositional phrase "to reporters"` },
  { s: `English Language`, q: `Fill in the blank with an appropriate adverb. Riya is ______ nervous. She hesitates to speak in public.`, o: [`genuinely`, `slightly`, `rather`, `beautifully`], e: `The correct option is (c). Explanation (adverb of degree): The blank needs an adverb that modifies the adjective "nervous" and matches the context: "She hesitates to speak in public." "Rather" is an adverb of degree meaning "to a considerable extent" or "quite," which correctly indicates a noticeable level of nervousness. (Hindi meaning: / ) This intensity fits the reason for hesitation in public speaking. Correct sentence: "Riya is rather nervous. She hesitates to speak in public." Example (correct word): He was rather surprised by the sudden announcement. Why other options are incorrect: (a) genuinely: means truly/sincerely ( ); it describes authenticity, not degree. (b) slightly: means a little (); it weakens the meaning and may not justify strong hesitation. (d) beautifully: means in a` },
  { s: `English Language`, q: `Pick the correctly spelled word referring to careful investigation.`, o: [`Scrutiny`, `Scrutiney`, `Scrootiny`, `Scrutini`], e: `The correct option is (a). Correct spelling and meaning: Option (a) "Scrutiny" is correctly spelt. It means careful and thorough examination or investigation to discover the truth or detect errors. (Hindi meaning: / ) Example: The accounts were placed under scrutiny after the audit revealed irregularities. Why other options are incorrect: (b) Scrutiney is incorrect because the ending "-ey" is not used in the correct spelling. (c) Scrootiny is incorrect because it wrongly inserts extra letters and changes the vowel sound. (d) Scrutini is incomplete and incorrect; the standard noun ends with "-ny." Meanings of all options: Scrutiny: careful examination ( ). Scrutiney: incorrect spelling ( ). Scrootiny: incorrect spelling ( ). Scrutini: incorrect/incomplete spelling ( ). So the correct answer` },
  { s: `English Language`, q: `Choose the correct meaning of idiom "throw down the gauntlet".`, o: [`Admit defeat openly`, `Offer an apology`, `Issue a bold challenge`, `Avoid a contest`], e: `The correct option is (c). Meaning of the idiom: Throw down the gauntlet means to challenge someone boldly, often inviting them to compete, fight, or prove themselves. Historically, a "gauntlet" was a knight's glove; throwing it down symbolized a formal challenge. (Hindi meaning/idiomatic sense: ) Example: The manager threw down the gauntlet by asking the team to beat last year's sales record. Why other options are incorrect: (a) "Admit defeat openly" is the opposite of challenging; it indicates surrender. (b) "Offer an apology" is unrelated to the idea of a challenge. (d) "Avoid a contest" contradicts the idiom's meaning. Other related idioms and meanings: Take up the gauntlet: accept a challenge ( ). Up the ante: increase the stakes/level of challenge ( ). Call someone out: challenge pub` },
  { s: `English Language`, q: `Arrange the parts to form a correct sentence: (1) She scanned the headline. (2) She unfolded the newspaper. (3) She sighed in disbelief. (4) She read the full report.`, o: [`1`, `2`, `2`, `4`], e: `The correct option is (b). Correct logical sequence: 2 1 4 3 Explanation of the sequence: (2) She unfolded the newspaper. This is the first physical action needed before reading anything. (1) She scanned the headline. After unfolding, a reader typically looks at the headline quickly. (4) She read the full report. Scanning the headline leads to reading the detailed report. (3) She sighed in disbelief. The emotional reaction logically comes after understanding the full content. Why other options are incorrect: (a) starts with scanning the headline before unfolding the paper, which is illogical. (c) places reading the full report before scanning the headline, which breaks natural reading order. (d) begins with reading the full report before unfolding the newspaper, which is impossible. So the` },
  { s: `English Language`, q: `Arrange the parts to form a correct sentence: (1) The final whistle blew. (2) The crowd erupted in cheers. (3) The team lifted the trophy. (4) Cameras flashed everywhere.`, o: [`2-1-3-4`, `3-1-2-4`, `1-2-3-4`, `4-2-1-3`], e: `The correct option is (c). Correct logical sequence: 1-2-3-4 Explanation of the sequence: (1) The final whistle blew. This signals the end of the match, so it must occur first. (2) The crowd erupted in cheers. Immediately after the whistle, spectators react with celebration. (3) The team lifted the trophy. Trophy lifting is the formal celebration after the match ends. (4) Cameras flashed everywhere. Media and cameras usually intensify during the victory moment and trophy celebration. Why other options are incorrect: (a) puts cheering before the final whistle, which is less logical for a concluding celebration. (b) places trophy lifting before the final whistle, which is not possible in a match context. (d) begins with cameras flashing, but the main trigger is typically the end-of-match res` },
  { s: `English Language`, q: `Choose the correct meaning of idiom "Hoist with one's own petard".`, o: [`Gain success through flattery`, `Be harmed by one's own plot`, `Win after hard work`, `Escape danger quickly`], e: `The correct option is (b). Meaning of the idiom: Hoist with one's own petard means to be harmed or defeated by one's own plan, trick, or plot intended for others. A "petard" was a small explosive; the idiom suggests the plotter is blown up by his own device. (Hindi meaning/idiomatic sense: / ) Example: He spread false rumours, but the truth came out and he was hoist with his own petard. Why other options are incorrect: (a) relates to flattery, which is not the idea here. (c) refers to success through effort, which is unrelated. (d) means escaping danger, which is opposite to being harmed by one's own plan. Other related idioms and meanings: Dig one's own grave: create one's own downfall ( ). Backfire: produce the opposite effect intended ( ). Catch-22: a situation with no good solution due` },
  { s: `English Language`, q: `Arrange the parts to form a correct sentence: P: the volunteers Q: launched a drive R: against food wastage S: on Monday in the locality`, o: [`PQRS`, `QPRS`, `PRQS`, `PSRQ`], e: `The correct option is (a). Correct sentence: Order PQRS forms: "The volunteers launched a drive against food wastage on Monday in the locality." Reasoning: P provides the subject "the volunteers," so it must come first. Q gives the main verb phrase "launched a drive," which should follow the subject. R explains the purpose/topic of the drive "against food wastage," which naturally follows "drive." S gives time and place details "on Monday in the locality," which commonly come after the main clause information. Why other options are incorrect: (b) begins with the verb phrase without the subject. (c) places "against food wastage" before the verb phrase, disrupting the standard structure. (d) inserts time/place before stating the action, making the sequence unnatural for the given parts. So t` },
  { s: `English Language`, q: `Find the part of the sentence that contains an error: The manuscript that had been missing for years (1)/ was found behind an old cabinet (2)/ and were later published by a reputed press (3)/ after careful editing. (4)`, o: [`The manuscript that had been missing for years (1)`, `was found behind an old cabinet (2)`, `and were later published by a reputed press (3)`, `after careful editing (4)`], e: `The correct option is (c). Error explanation: Option (c) is incorrect because it violates subject┬şverb agreement and parallel verb structure. The subject of the sentence is "The manuscript", which is singular. Earlier verb: "was found" (singular) correctly agrees with "manuscript." In option (c), the verb phrase is "were later published," which is plural and does not agree with the singular subject. Correct form: "...and was later published by a reputed press..." Grammatical rule used: A singular subject takes a singular verb, and coordinated verb phrases connected with "and" should maintain correct agreement with the same subject. Example (rule usage): The report was prepared and was submitted on time. Why other parts are correct: (a) correctly uses a past perfect passive clause "had been` },
  { s: `English Language`, q: `Arrange the following parts to form a coherent and meaningful paragraph:`, o: [`A`, `A`, `C`, `D`], e: `The correct option is (a). Correct coherent sequence: A C D B Explanation of the paragraph flow: A is the natural beginning because an event commonly starts with the host welcoming guests. C follows because after being welcomed, the audience settles and takes their seats. D logically comes next as the performers enter the stage once the audience is seated. B is the concluding event cue: lights dim and the show begins, which typically happens immediately before performance starts. Why other options are incorrect: (b) starts the show (lights dimmed) before performers enter, which makes the sequence less natural. (c) puts the audience seating before the host's welcome, which is possible but not the most coherent with the given statements. (d) begins with performers entering before welcome and` },
  { s: `English Language`, q: `Choose the correct one-word substitution for: "A belief that God is present in everything and the universe is divine."`, o: [`Pantheism`, `Monotheism`, `Atheism`, `Skepticism`], e: `The correct option is (a). The correct one-word for the given group of words is (a) Pantheism. Explanation: Pantheism is the belief that God and the universe are identical, and that the divine is present in everything in nature and existence. It treats the whole universe as sacred or divine rather than separating God from creation. (Hindi meaning: / ) Example: Many philosophers described their view of nature as pantheism because they believed the divine exists in all things. Meanings of the other options: (b) Monotheism: belief in one God ( ). (c) Atheism: belief that God does not exist (). (d) Skepticism: doubt or questioning attitude, especially toward accepted beliefs (). So the correct answer is (a)` },
  { s: `English Language`, q: `Arrange the parts to form a correct sentence: P: many colleges Q: joined R: in Jaipur S: the cleanliness campaign`, o: [`RPSQ`, `PRSQ`, `PQSR`, `QPSR`], e: `The correct option is (c). Correct order: PQSR Formed sentence: "Many colleges joined the cleanliness campaign in Jaipur." Reasoning: P "many colleges" is the subject, so it should come first. Q "joined" is the main verb and must follow the subject. S "the cleanliness campaign" is the object of "joined," so it must come after the verb. R "in Jaipur" is a place phrase that suitably comes at the end to complete the meaning. Why other options are incorrect: (a) RPSQ begins with the place phrase, which is not the normal order for this simple sentence. (b) PRSQ places "in Jaipur" before the verb "joined," disrupting subject┬şverb sequence. (d) QPSR starts with a verb without a subject, making it incorrect. So the correct answer is (c)` },
  { s: `English Language`, q: `Convert the sentence provided below from its passive voice structure to an active voice structure: The final list will be displayed by the school tomorrow.`, o: [`The school will display the final list tomorrow.`, `The school is displaying the final list tomorrow.`, `The final list was displayed by the school tomorrow.`, `The school has displayed the final list tomorrow.`], e: `The correct option is (a). Step-by-step conversion (Passive to Active): Identify the tense: "will be displayed" is Simple Future Passive. Passive structure: Object + will be + V3 + by + agent. Active structure: Agent + will + V1 + object. Agent: "the school" becomes the subject. Object: "the final list" becomes the object. Time expression "tomorrow" remains unchanged. Correct active sentence: "The school will display the final list tomorrow." Why other options are incorrect: (b) changes the tense to Present Continuous, which is not the same as "will be displayed." (c) keeps passive voice and also wrongly shifts tense to past. (d) uses Present Perfect, which is incorrect with the future time marker "tomorrow." So the correct answer is (a)` }
];

if (RAW.length !== 100) { console.error(`Expected 100 questions, got ${RAW.length}`); process.exit(1); }

async function seed() {
  console.log('Connecting to MongoDB...');
  await mongoose.connect(MONGO_URI);
  console.log('Connected.');

  let category = await ExamCategory.findOne({ name: 'Central', type: 'Central' });
  if (!category) {
    category = await ExamCategory.create({ name: 'Central', type: 'Central', description: 'Central government competitive exams' });
  }

  let exam = await Exam.findOne({ code: 'SSC-SSP-HS' });
  if (!exam) {
    exam = await Exam.create({
      category: category._id,
      name: 'SSC Selection Post (Higher Secondary Level)',
      code: 'SSC-SSP-HS',
      description: 'Staff Selection Commission - Selection Post (Higher Secondary Level)',
      isActive: true
    });
  }

  const PATTERN_TITLE = 'SSC Selection Post (Higher Secondary Level)';
  let pattern = await ExamPattern.findOne({ exam: exam._id, title: PATTERN_TITLE });
  if (!pattern) {
    pattern = await ExamPattern.create({
      exam: exam._id, title: PATTERN_TITLE, duration: 60, totalMarks: 200, negativeMarking: 0.5,
      sections: [
        { name: REA, totalQuestions: 25, marksPerQuestion: 2, negativePerQuestion: 0.5 },
        { name: GA,  totalQuestions: 25, marksPerQuestion: 2, negativePerQuestion: 0.5 },
        { name: QA,  totalQuestions: 25, marksPerQuestion: 2, negativePerQuestion: 0.5 },
        { name: ENG, totalQuestions: 25, marksPerQuestion: 2, negativePerQuestion: 0.5 }
      ]
    });
  }

  const TEST_TITLE = 'SSC Selection Post (Higher Secondary) - 24 July 2025 Shift-2 [Similar Paper]';
  await PracticeTest.deleteMany({ examPattern: pattern._id, title: TEST_TITLE });

  const questions = RAW.map((r, i) => ({
    questionText: r.q,
    questionImage: '',
    options: r.o,
    optionImages: ['', '', '', ''],
    correctAnswerIndex: KEY[i] - 1,
    explanation: r.e || '',
    section: r.s,
    tags: ['SSC', 'Selection Post', 'Phase XIII', 'Higher Secondary', 'PYQ', '2025', 'Similar Paper'],
    difficulty: 'medium'
  }));

  const test = await PracticeTest.create({
    examPattern: pattern._id, title: TEST_TITLE, totalMarks: 200, duration: 60,
    accessLevel: 'FREE', isPYQ: true, pyqYear: 2025, pyqShift: '2',
    pyqExamName: 'SSC Selection Post Phase XIII (Higher Secondary) - Similar Paper', questions
  });
  console.log(`Created PYQ PracticeTest: ${test._id} (${test.questions.length} questions)`);

  await mongoose.disconnect();
  console.log('Done.');
}

seed().catch(err => { console.error('Seed failed:', err); process.exit(1); });
